import React, { useRef, useState, useEffect } from "react";
import { CsvRow } from "../utils/csvUtils";

interface ResultsTableProps {
  rows: CsvRow[];
  onSelectRows: (rows: CsvRow[]) => void;
  selectedRows: CsvRow[];
}

const INITIAL_ROWS = 30;
const LOAD_MORE_ROWS = 20;

const ResultsTable: React.FC<ResultsTableProps> = ({ rows, onSelectRows }) => {
  const [visibleCount, setVisibleCount] = useState(INITIAL_ROWS);
  const containerRef = useRef<HTMLDivElement>(null);
  const [selected, setSelected] = useState<Set<number>>(new Set());

  useEffect(() => {
    setVisibleCount(INITIAL_ROWS);
    setSelected(new Set());
  }, [rows]);

  const handleScroll = () => {
    const container = containerRef.current;
    if (
      container &&
      container.scrollTop + container.clientHeight >= container.scrollHeight - 10
    ) {
      setVisibleCount((prev) => Math.min(prev + LOAD_MORE_ROWS, rows.length));
    }
  };

  const handleSelect = (idx: number) => {
    setSelected((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(idx)) {
        newSet.delete(idx);
      } else {
        newSet.add(idx);
      }
      return newSet;
    });
  };

  const handleAddSelected = () => {
    const selectedRows = Array.from(selected).map(idx => rows[idx]);
    onSelectRows(selectedRows);
    setSelected(new Set());
  };

  if (!rows || rows.length === 0) {
    return <div>Nenhum resultado encontrado.</div>;
  }

  const headers = Object.keys(rows[0]);
  const visibleRows = rows.slice(0, visibleCount);

  return (
    <div>
      <div
        ref={containerRef}
        style={{ maxHeight: 400, overflowY: "auto", border: "1px solid #eee" }}
        onScroll={handleScroll}
      >
        <table>
          <thead>
            <tr>
              <th></th>
              {headers.map((header) => (
                <th key={header}>{header}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {visibleRows.map((row, idx) => (
              <tr key={idx}>
                <td>
                  <input
                    type="checkbox"
                    checked={selected.has(idx)}
                    onChange={() => handleSelect(idx)}
                  />
                </td>
                {headers.map((header) => (
                  <td key={header}>{row[header]}</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <button
        onClick={handleAddSelected}
        disabled={selected.size === 0}
        style={{ marginTop: 12 }}
      >
        Adicionar selecionados
      </button>
    </div>
  );
};

export default ResultsTable;
